import { Component, OnInit } from '@angular/core';
import { MagicService } from '../../services/magic.service';


@Component({
  selector: 'app-magias',
  templateUrl: './magias.component.html',
  styleUrls: ['./magias.component.css']
})
export class MagiasComponent implements OnInit{

  magias: any[] = [];
  selectedMagia: any = null;

  constructor(private magicService: MagicService) {}

  ngOnInit(): void {
    this.magicService.getMagias().subscribe((data) => {
      this.magias = data;
    });
  }

  selectMagia(id: string): void {
    this.magicService.getMagiaDetalhe(id).subscribe((data) => {
      this.selectedMagia = data;
    });
  }

}
